tests.source_program:
define i64 @test_shl_by_2(i64 %x) !prof !0 {
  %x1 = add i64 %x, 1
  %shl = shl nuw i64 %x, 2
  %max = call i64 @llvm.umax.i64(i64 %shl, i64 %x1)
  ret i64 %max
}
